import{_ as e,c as r,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"高度な機能: 圧縮原理と設定解説 | opencode-supermemory","description":"Supermemory の先制圧縮原理と詳細設定オプションを学びます。記憶エンジンの最適化とプラグインのカスタマイズ方法を理解します。","frontmatter":{"title":"高度な機能: 圧縮原理と設定解説 | opencode-supermemory","sidebarTitle":"高度な機能","subtitle":"高度な機能: 圧縮原理と設定解説","description":"Supermemory の先制圧縮原理と詳細設定オプションを学びます。記憶エンジンの最適化とプラグインのカスタマイズ方法を理解します。","order":3},"headers":[],"relativePath":"ja/supermemoryai/opencode-supermemory/advanced/index.md","filePath":"ja/supermemoryai/opencode-supermemory/advanced/index.md"}'),n={name:"ja/supermemoryai/opencode-supermemory/advanced/index.md"};function t(i,a,l,p,c,d){return o(),r("div",null,[...a[0]||(a[0]=[s(`<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><p>この章では Supermemory の底層メカニズムと高度な設定オプションを深く説明します。記憶エンジンのパフォーマンスを最適化し、プロジェクトの要件に応じてプラグインの動作をカスタマイズする方法を学びます。</p><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><div class="grid-cards"><h3 id="先制圧縮の原理" tabindex="-1"><a href="./compaction/">先制圧縮の原理</a> <a class="header-anchor" href="#先制圧縮の原理" aria-label="Permalink to &quot;[先制圧縮の原理](./compaction/)&quot;">​</a></h3><p>トークンしきい値でトリガーされる自動圧縮メカニズムを深く理解します。Supermemory がコンテキストがオーバーフローする前に、構造化された要約を能動的に生成して永続的に保存し、長いセッションでの「記憶喪失」問題を防ぐ方法を学びます。</p><h3 id="詳細設定の解説" tabindex="-1"><a href="./configuration/">詳細設定の解説</a> <a class="header-anchor" href="#詳細設定の解説" aria-label="Permalink to &quot;[詳細設定の解説](./configuration/)&quot;">​</a></h3><p>圧縮しきい値、キーワードトリガールール、検索パラメータをカスタマイズします。設定ファイルのすべてのオプションをマスターし、Supermemory をあなたのワークフローに完璧に適応させます。</p></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ステップ 1             ステップ 2                             │</span></span>
<span class="line"><span>│  先制圧縮の原理   →   詳細設定の解説                           │</span></span>
<span class="line"><span>│  (メカニズムの理解)     (カスタマイズ実践)                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>推奨順序</strong>：</p><ol><li><strong>まず圧縮原理を学ぶ</strong>：Supermemory がコンテキストを自動的に管理する方法を理解します。これは高度な設定の基礎です。</li><li><strong>次に設定の解説を学ぶ</strong>：メカニズムを理解した後、合理的な設定決定（例：しきい値をいくつに設定するのが適切か）ができるようになります。</li></ol><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前の確認</p><p>本章の内容は、以下の学習が完了していることを前提としています：</p><ul><li>✅ <a href="./../start/getting-started/">クイックスタート</a>：プラグインをインストールし、API Key を設定済み</li><li>✅ <a href="./../core/memory-management/">記憶スコープとライフサイクル</a>：User Scope と Project Scope の違いを理解済み</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章を完了したら、以下を続けて学習することをお勧めします：</p><ul><li><strong><a href="./../security/privacy/">プライバシーとデータセキュリティ</a></strong>：センシティブデータの自動検閲メカニズムを理解し、コードやキーが誤ってアップロードされないようにします。</li></ul>`,13)])])}const u=e(n,[["render",t]]);export{h as __pageData,u as default};
